    "inlineSchema": "// This is your Prisma schema file,\n// learn more about it in the docs: https://pris.ly/d/prisma-schema\n\n// Get a free hosted Postgres database in seconds: `npx create-db`\n\ngenerator client {\n  provider = \"prisma-client\"\n  output   = \"../src/generated/prisma\"\n}\n\ndatasource db {\n  provider = \"postgresql\"\n}\n\nenum UserRole {\n  ORGANIZER\n  REVIEWER\n  PARTICIPANT\n}\n\nenum TicketType {\n  FREE\n  PAID\n}\n\nenum TicketStatus {\n  PENDING\n  COMPLETED\n  CANCELLED\n}\n\nenum SubmissionStatus {\n  SUBMITTED\n  UNDER_REVIEW\n  ACCEPTED\n  REJECTED\n}\n\nenum EventStatus {\n  DRAFT\n  PUBLISHED\n  ARCHIVED\n}\n\nenum ActivityStatus {\n  SCHEDULED\n  CANCELLED\n  COMPLETED\n}\n\nenum FormType {\n  REGISTRATION\n  SUBMISSION\n}\n\nenum FormFieldType {\n  TEXT\n  TEXTAREA\n  SELECT\n  MULTISELECT\n  CHECKBOX\n  DATE\n  NUMBER\n  EMAIL\n}\n\nenum ReviewRecommendation {\n  STRONG_ACCEPT\n  ACCEPT\n  WEAK_ACCEPT\n  BORDERLINE\n  WEAK_REJECT\n  REJECT\n  STRONG_REJECT\n}\n\nmodel Tenant {\n  id        String   @id @default(cuid())\n  name      String\n  slug      String   @unique\n  createdAt DateTime @default(now())\n  updatedAt DateTime @updatedAt\n\n  users    User[]\n  events   Event[]\n  speakers Speaker[]\n}\n\nmodel User {\n  id        String   @id @default(cuid())\n  email     String   @unique\n  password  String\n  name      String\n  role      UserRole\n  createdAt DateTime @default(now())\n  updatedAt DateTime @updatedAt\n\n  tenantId String\n  tenant   Tenant @relation(fields: [tenantId], references: [id])\n\n  registrations Registration[]\n  reviews       Review[]\n  submissions   Submission[]   @relation(\"SubmissionAuthor\")\n}\n\nmodel Event {\n  id       String @id @default(cuid())\n  tenantId String\n  tenant   Tenant @relation(fields: [tenantId], references: [id])\n\n  name        String\n  slug        String\n  description String?\n  location    String?\n  startDate   DateTime\n  endDate     DateTime\n  status      EventStatus @default(DRAFT)\n\n  bannerUrl      String?\n  logoUrl        String?\n  themeConfig    Json?\n  seoTitle       String?\n  seoDescription String?\n\n  createdAt DateTime @default(now())\n  updatedAt DateTime @updatedAt\n\n  activities           Activity[]\n  registrations        Registration[]\n  tickets              Ticket[]\n  forms                CustomForm[]\n  submissions          Submission[]\n  certificateTemplates CertificateTemplate[]\n\n  @@unique([tenantId, slug])\n}\n\nmodel Activity {\n  id      String @id @default(cuid())\n  eventId String\n  event   Event  @relation(fields: [eventId], references: [id])\n\n  title       String\n  description String?\n  location    String?\n  startAt     DateTime\n  endAt       DateTime\n  capacity    Int?\n  status      ActivityStatus @default(SCHEDULED)\n\n  createdAt DateTime @default(now())\n  updatedAt DateTime @updatedAt\n\n  speakers    ActivitySpeaker[]\n  enrollments ActivityEnrollment[]\n  attendances Attendance[]\n}\n\nmodel Speaker {\n  id       String @id @default(cuid())\n  tenantId String\n  tenant   Tenant @relation(fields: [tenantId], references: [id])\n\n  name      String\n  bio       String?\n  avatarUrl String?\n\n  createdAt DateTime @default(now())\n  updatedAt DateTime @updatedAt\n\n  activities ActivitySpeaker[]\n}\n\nmodel ActivitySpeaker {\n  activityId String\n  speakerId  String\n\n  activity Activity @relation(fields: [activityId], references: [id])\n  speaker  Speaker  @relation(fields: [speakerId], references: [id])\n\n  @@id([activityId, speakerId])\n}\n\nmodel Registration {\n  id      String @id @default(cuid())\n  eventId String\n  event   Event  @relation(fields: [eventId], references: [id])\n\n  userId String\n  user   User   @relation(fields: [userId], references: [id])\n\n  createdAt DateTime @default(now())\n\n  tickets       Ticket[]\n  enrollments   ActivityEnrollment[]\n  formResponses CustomFormResponse[]\n  certificates  IssuedCertificate[]\n}\n\nmodel ActivityEnrollment {\n  id         String   @id @default(cuid())\n  activityId String\n  activity   Activity @relation(fields: [activityId], references: [id])\n\n  registrationId String\n  registration   Registration @relation(fields: [registrationId], references: [id])\n\n  createdAt DateTime @default(now())\n}\n\nmodel Ticket {\n  id      String @id @default(cuid())\n  eventId String\n  event   Event  @relation(fields: [eventId], references: [id])\n\n  registrationId String\n  registration   Registration @relation(fields: [registrationId], references: [id])\n\n  type   TicketType   @default(FREE)\n  status TicketStatus @default(PENDING)\n  price  Decimal      @default(0)\n\n  qrCodeToken String? @unique\n\n  createdAt DateTime @default(now())\n  updatedAt DateTime @updatedAt\n\n  attendances Attendance[]\n}\n\nmodel CustomForm {\n  id      String @id @default(cuid())\n  eventId String\n  event   Event  @relation(fields: [eventId], references: [id])\n\n  name String\n  type FormType\n\n  createdAt DateTime @default(now())\n  updatedAt DateTime @updatedAt\n\n  fields    CustomFormField[]\n  responses CustomFormResponse[]\n}\n\nmodel CustomFormField {\n  id     String     @id @default(cuid())\n  formId String\n  form   CustomForm @relation(fields: [formId], references: [id])\n\n  label    String\n  type     FormFieldType\n  required Boolean       @default(false)\n  order    Int\n  options  Json?\n\n  createdAt DateTime @default(now())\n  updatedAt DateTime @updatedAt\n\n  answers CustomFormAnswer[]\n}\n\nmodel CustomFormResponse {\n  id     String     @id @default(cuid())\n  formId String\n  form   CustomForm @relation(fields: [formId], references: [id])\n\n  registrationId String?\n  registration   Registration? @relation(fields: [registrationId], references: [id])\n\n  submissionId String?\n  submission   Submission? @relation(fields: [submissionId], references: [id])\n\n  createdAt DateTime @default(now())\n\n  answers CustomFormAnswer[]\n}\n\nmodel CustomFormAnswer {\n  id         String             @id @default(cuid())\n  responseId String\n  response   CustomFormResponse @relation(fields: [responseId], references: [id])\n\n  fieldId String\n  field   CustomFormField @relation(fields: [fieldId], references: [id])\n\n  value String\n}\n\nmodel Submission {\n  id      String @id @default(cuid())\n  eventId String\n  event   Event  @relation(fields: [eventId], references: [id])\n\n  authorId String\n  author   User   @relation(\"SubmissionAuthor\", fields: [authorId], references: [id])\n\n  title    String\n  abstract String?\n  fileUrl  String\n  status   SubmissionStatus @default(SUBMITTED)\n\n  createdAt DateTime @default(now())\n  updatedAt DateTime @updatedAt\n\n  reviews       Review[]\n  formResponses CustomFormResponse[]\n}\n\nmodel Review {\n  id           String     @id @default(cuid())\n  submissionId String\n  submission   Submission @relation(fields: [submissionId], references: [id])\n\n  reviewerId String\n  reviewer   User   @relation(fields: [reviewerId], references: [id])\n\n  score          Int?\n  recommendation ReviewRecommendation?\n  comments       String?\n\n  createdAt DateTime @default(now())\n}\n\nmodel Attendance {\n  id String @id @default(cuid())\n\n  ticketId String\n  ticket   Ticket @relation(fields: [ticketId], references: [id])\n\n  activityId String?\n  activity   Activity? @relation(fields: [activityId], references: [id])\n\n  checkedAt DateTime @default(now())\n}\n\nmodel CertificateTemplate {\n  id      String @id @default(cuid())\n  eventId String\n  event   Event  @relation(fields: [eventId], references: [id])\n\n  name          String\n  backgroundUrl String\n  layoutConfig  Json // Coordenadas e estilos vindos do frontend\n\n  createdAt DateTime @default(now())\n  updatedAt DateTime @updatedAt\n\n  issuedCertificates IssuedCertificate[]\n}\n\nmodel IssuedCertificate {\n  id String @id @default(cuid())\n\n  templateId String\n  template   CertificateTemplate @relation(fields: [templateId], references: [id])\n\n  registrationId String\n  registration   Registration @relation(fields: [registrationId], references: [id])\n\n  fileUrl  String\n  issuedAt DateTime @default(now())\n}\n",
